module.render:
const rawCss = (sections[0] || '').trim();
const inner = (sections[1] || '').trim();
// Forgiving: with no second section (missing `<!-- @ -->` separator), the
// single section is the CONTENT, not CSS — otherwise an image/text put there
// would be swallowed into a <style> tag and vanish.
if (!inner) {
  return `\n\n${rawCss}\n\n`;
}
// The CSS may be wrapped in an HTML comment (<!-- … -->) so a PLAIN Markdown
// viewer hides it — unwrap it here. Only when the whole section is one comment.
let cssText = rawCss;
if (cssText.slice(0, 4) === '<!--' && cssText.slice(-3) === '-->') {
  cssText = cssText.slice(4, -3).trim();
}
// Deterministic, instance-unique scope class from the CSS + content.
let h = 0;
const sig = cssText + '|' + inner;
for (let i = 0; i < sig.length; i++) h = (h * 31 + sig.charCodeAt(i)) | 0;
const scope = 'mdpscope-' + Math.abs(h).toString(36);
// Prefix each rule's selectors with the scope class (flat rules; @-rules left
// as-is). This keeps the CSS from leaking to other diagrams/slides.
const scoped = cssText.replace(/([^{}]+)\{([^{}]*)\}/g, (_m, sel, body) => {
  const sl = String(sel).split(',').map(function (x) { return x.trim(); })
    .filter(Boolean)
    .map(function (x) { return x.charAt(0) === '@' ? x : '.' + scope + ' ' + x; })
    .join(', ');
  return sl + ' { ' + body + ' }';
});
return `\n\n<style>${scoped}</style>\n\n<div class="${scope}">\n\n${inner}\n\n</div>\n\n`;
